config.solution_code:
class Contact:
    def __init__(self, name, phone, email):
        self.name = name
        self.phone = phone
        self.email = email

    def __str__(self):
        return f"{self.name}: {self.phone}, {self.email}"

class ContactBook:
    def __init__(self):
        self.contacts = {}

    def add(self, name, phone, email):
        self.contacts[name] = Contact(name, phone, email)

    def search(self, name):
        if name in self.contacts:
            print(self.contacts[name])
        else:
            print("Not found")

    def list_all(self):
        for name in sorted(self.contacts.keys()):
            print(self.contacts[name])

n = int(input())
book = ContactBook()
for _ in range(n):
    parts = input().split()
    command = parts[0]
    if command == "ADD":
        book.add(parts[1], parts[2], parts[3])
    elif command == "SEARCH":
        book.search(parts[1])
    elif command == "LIST":
        book.list_all()
